// Load validation rules based on document category and client
const document = $input.first().json;

const category = document.category || 'other';
const clientId = document.client_id;
const extractedData = document.result_data || {};
const confidence = document.confidence_score || 0.7;

// Define validation rules per category
const validationRules = {
  invoice: {
    requiredFields: ['invoice_number', 'date', 'total_amount'],
    optionalFields: ['vendor', 'due_date', 'tax_amount'],
    fieldValidation: {
      invoice_number: { type: 'string', minLength: 3, maxLength: 50 },
      date: { type: 'date', format: 'YYYY-MM-DD' },
      total_amount: { type: 'number', min: 0, max: 1000000 }
    },
    businessRules: [
      { name: 'due_date_after_invoice_date', check: (data) => !data.due_date || new Date(data.due_date) >= new Date(data.date) }
    ]
  },

  contract: {
    requiredFields: ['contract_number', 'start_date'],
    optionalFields: ['parties', 'end_date', 'value'],
    fieldValidation: {
      contract_number: { type: 'string', minLength: 5 },
      start_date: { type: 'date' }
    },
    businessRules: []
  },

  resume: {
    requiredFields: ['email'],
    optionalFields: ['name', 'phone', 'skills', 'experience_years'],
    fieldValidation: {
      email: { type: 'email' },
      phone: { type: 'string', pattern: /^[\d\s-+()]{10,}$/ }
    },
    businessRules: []
  },

  receipt: {
    requiredFields: ['total'],
    optionalFields: ['date', 'vendor', 'items'],
    fieldValidation: {
      total: { type: 'number', min: 0 }
    },
    businessRules: []
  },

  default: {
    requiredFields: [],
    optionalFields: ['text_content'],
    fieldValidation: {},
    businessRules: []
  }
};

// Get rules for this category
const rules = validationRules[category] || validationRules.default;

// Prepare validation data
const validationData = {
  document_id: document.document_id,
  document_uuid: document.document_uuid,
  client_id: clientId,
  original_filename: document.original_filename,
  category: category,
  extracted_data: extractedData,
  confidence_score: confidence,
  validation_rules: rules,
  timestamp: new Date().toISOString()
};

return [{ json: validationData }];

// Validate extracted data against rules
const data = $input.first().json;
const extractedData = data.extracted_data || {};
const rules = data.validation_rules;

let validationResults = {
  is_valid: true,
  errors: [],
  warnings: [],
  field_validations: {},
  business_rule_validations: [],
  overall_score: 0
};

// Check required fields
rules.requiredFields.forEach(field => {
  if (!extractedData[field]) {
    validationResults.errors.push(`Missing required field: ${field}`);
    validationResults.is_valid = false;
    validationResults.field_validations[field] = {
      passed: false,
      error: 'Field is required'
    };
  } else {
    validationResults.field_validations[field] = {
      passed: true,
      value: extractedData[field]
    };
  }
});

// Validate field formats and constraints
rules.fieldValidation && Object.keys(rules.fieldValidation).forEach(field => {
  const value = extractedData[field];
  const validation = rules.fieldValidation[field];

  if (value !== undefined && value !== null) {
    let fieldPassed = true;
    let fieldError = '';

    // Type validation
    if (validation.type === 'number') {
      if (isNaN(parseFloat(value))) {
        fieldPassed = false;
        fieldError = `Field ${field} must be a number`;
      } else {
        const numValue = parseFloat(value);
        if (validation.min !== undefined && numValue < validation.min) {
          fieldPassed = false;
          fieldError = `Field ${field} must be at least ${validation.min}`;
        }
        if (validation.max !== undefined && numValue > validation.max) {
          fieldPassed = false;
          fieldError = `Field ${field} must be at most ${validation.max}`;
        }
      }
    } else if (validation.type === 'email') {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(value)) {
        fieldPassed = false;
        fieldError = `Field ${field} must be a valid email`;
      }
    } else if (validation.type === 'string') {
      if (validation.minLength && value.length < validation.minLength) {
        fieldPassed = false;
        fieldError = `Field ${field} must be at least ${validation.minLength} characters`;
      }
      if (validation.maxLength && value.length > validation.maxLength) {
        fieldPassed = false;
        fieldError = `Field ${field} must be at most ${validation.maxLength} characters`;
      }
    } else if (validation.type === 'date') {
      const date = new Date(value);
      if (isNaN(date.getTime())) {
        fieldPassed = false;
        fieldError = `Field ${field} must be a valid date`;
      }
    }

    if (validation.pattern && !validation.pattern.test(value)) {
      fieldPassed = false;
      fieldError = `Field ${field} does not match required pattern`;
    }

    validationResults.field_validations[field] = {
      passed: fieldPassed,
      value: value,
      error: fieldPassed ? null : fieldError
    };

    if (!fieldPassed) {
      validationResults.errors.push(fieldError);
      validationResults.is_valid = false;
    }
  }
});

// Check optional fields (warnings only)
rules.optionalFields && rules.optionalFields.forEach(field => {
  if (!extractedData[field]) {
    validationResults.warnings.push(`Optional field ${field} is missing`);
  }
});

// Run business rules
rules.businessRules && rules.businessRules.forEach(rule => {
  try {
    const rulePassed = rule.check(extractedData);
    validationResults.business_rule_validations.push({
      name: rule.name,
      passed: rulePassed
    });
    if (!rulePassed) {
      validationResults.errors.push(`Business rule failed: ${rule.name}`);
      validationResults.is_valid = false;
    }
  } catch (error) {
    validationResults.warnings.push(`Could not evaluate business rule: ${rule.name}`);
  }
});

// Calculate overall validation score
const totalChecks = Object.keys(validationResults.field_validations).length + 
                   validationResults.business_rule_validations.length;
const passedChecks = Object.values(validationResults.field_validations).filter(v => v.passed).length +
                     validationResults.business_rule_validations.filter(v => v.passed).length;
validationResults.overall_score = totalChecks > 0 ? (passedChecks / totalChecks) * 100 : 0;

// Combine with extraction confidence
validationResults.combined_score = (validationResults.overall_score * 0.6) + (data.confidence_score * 40);

const result = {
  document_id: data.document_id,
  document_uuid: data.document_uuid,
  client_id: data.client_id,
  validation_results: validationResults,
  validated_at: new Date().toISOString()
};

return [{ json: result }];
